+                "maximum": 100,
+                "description": "A count"
+            }
+        }
+    });
+    let doc = parse_schema(&schema);
+    assert_eq!(doc.properties[0].minimum, Some(0.0));
+    assert_eq!(doc.properties[0].maximum, Some(100.0));
+}
+
+// =========================================================================
+// categorize_endpoint
+// =========================================================================
